#!/usr/bin/env python3
"""Diffusers-backed FLUX text-to-image bridge for full FLUX KNOT files.

This is the practical "working FLUX" path while the native Rust kernels are
still admission-only. The KNOT remains the source of model weights. Diffusers is
used for the already-proven FLUX pipeline math, tokenizers, configs, and
scheduler wiring.

The script intentionally does not download model weights from Diffusers. It only
downloads or reads config/tokenizer/scheduler files from ``--model``; all
transformer, VAE, CLIP, and T5 tensors must be present in ``--knot``.
"""
from __future__ import annotations

import argparse
import importlib.util
import inspect
import json
import os
import struct
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any


FLUX_COMPONENT_POLICY = "flux-with-vae-text-encoders"
FLUX_WEIGHT_COMPONENTS = ("transformer", "vae", "text_encoder", "text_encoder_2")
FLUX_NON_WEIGHT_COMPONENTS = ("tokenizer", "tokenizer_2", "scheduler", "feature_extractor")
FLUX_COMPONENT_PREFIXES = {
    "transformer": ("flux_img_in_", "flux_dbl_", "flux_sgl_"),
    "vae": ("flux_vae_",),
    "text_encoder": ("flux_clip_",),
    "text_encoder_2": ("flux_t5_",),
}


@dataclass(frozen=True)
class KnotHeader:
    metadata: dict[str, Any]
    payload_offset: int


@dataclass(frozen=True)
class TensorPlan:
    key: str
    split_kind: str | None = None
    split_index: int = 0
    swap_scale_shift: bool = False


def read_knot_header(path: Path) -> KnotHeader:
    with path.open("rb") as handle:
        magic = handle.read(4)
        if magic != b"KNOT":
            raise ValueError(f"{path} is not a KNOT file")
        version = struct.unpack("<H", handle.read(2))[0]
        if version != 1:
            raise ValueError(f"{path} has unsupported KNOT version {version}")
        meta_len = struct.unpack("<I", handle.read(4))[0]
        metadata = json.loads(handle.read(meta_len).decode("utf-8"))

    header_len = 10 + meta_len
    padded_header_len = header_len + ((-header_len) % 4)
    return KnotHeader(metadata=metadata, payload_offset=padded_header_len + 1)


def validate_flux_knot_metadata(metadata: dict[str, Any]) -> list[str]:
    config = metadata.get("config")
    config_arch = config.get("arch") if isinstance(config, dict) else None
    arch = metadata.get("arch") or config_arch
    if arch != "flux":
        return [f"metadata arch must be 'flux', got {arch!r}"]

    problems: list[str] = []
    components = metadata.get("components")
    if not isinstance(components, dict):
        problems.append("missing top-level components metadata")
    else:
        included = set(components.get("included") or [])
        skipped = set(components.get("skipped") or [])
        if components.get("policy") != FLUX_COMPONENT_POLICY:
            problems.append(f"components.policy must be {FLUX_COMPONENT_POLICY!r}")
        for component in FLUX_WEIGHT_COMPONENTS:
            if component not in included:
                problems.append(f"components.included missing {component}")
        for component in FLUX_NON_WEIGHT_COMPONENTS:
            if component not in skipped:
                problems.append(f"components.skipped missing {component}")

    tensors = metadata.get("tensors")
    if not isinstance(tensors, dict):
        problems.append("missing tensor metadata table")
        return problems

    for component, prefixes in FLUX_COMPONENT_PREFIXES.items():
        matches = [
            (name, info)
            for name, info in tensors.items()
            if any(name.startswith(prefix) for prefix in prefixes)
        ]
        if not matches:
            problems.append(f"missing {component} tensors")
            continue
        shapeless = [
            name
            for name, info in matches
            if (
                not isinstance(info, dict)
                or not isinstance(info.get("shape"), list)
                or len(info["shape"]) == 0
            )
        ]
        if shapeless:
            sample = ", ".join(shapeless[:3])
            suffix = "..." if len(shapeless) > 3 else ""
            problems.append(f"{component} tensors missing shape metadata: {sample}{suffix}")

    return problems


def _numel(shape: list[int] | tuple[int, ...]) -> int:
    total = 1
    for dim in shape:
        total *= int(dim)
    return total


def dequantize_q8_0(raw: bytes, shape: list[int] | tuple[int, ...]):
    import numpy as np

    if len(raw) % 34 != 0:
        raise ValueError(f"Q8_0 tensor length must be a multiple of 34, got {len(raw)}")
    blocks = np.frombuffer(raw, dtype=np.uint8).reshape(-1, 34)
    scales = blocks[:, :2].copy().view(np.float16).astype(np.float32).reshape(-1, 1)
    quantized = blocks[:, 2:].copy().view(np.int8).astype(np.float32)
    values = (quantized * scales).reshape(-1)
    return values[: _numel(shape)].reshape(tuple(int(dim) for dim in shape))


class KnotTensorReader:
    def __init__(self, path: Path):
        self.path = path
        header = read_knot_header(path)
        self.metadata = header.metadata
        self.payload_offset = header.payload_offset
        tensors = self.metadata.get("tensors")
        if not isinstance(tensors, dict):
            raise ValueError("KNOT metadata is missing tensor table")
        self.tensors = tensors

    def read_numpy(self, key: str):
        import numpy as np

        info = self.tensors.get(key)
        if not isinstance(info, dict):
            raise KeyError(key)
        shape = info.get("shape")
        if not isinstance(shape, list) or not shape:
            raise ValueError(f"{key} is missing shape metadata")
        offset = int(info["offset"])
        length = int(info["length"])
        tensor_type = str(info.get("type") or "F32")
        with self.path.open("rb") as handle:
            handle.seek(self.payload_offset + offset)
            raw = handle.read(length)
        if len(raw) != length:
            raise ValueError(f"{key} truncated: wanted {length} bytes, got {len(raw)}")
        if tensor_type == "F32":
            return np.frombuffer(raw, dtype="<f4").reshape(tuple(shape))
        if tensor_type == "Q8_0":
            return dequantize_q8_0(raw, shape)
        raise ValueError(f"{key} has unsupported tensor type {tensor_type!r}")


def load_encode_knot_module():
    script_path = Path(__file__).resolve().with_name("encode-knot.py")
    spec = importlib.util.spec_from_file_location("encode_knot_for_flux_bridge", script_path)
    if spec is None or spec.loader is None:
        raise RuntimeError(f"could not load {script_path}")
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def canonical_to_tensor_key(canonical_name: str) -> str:
    return canonical_name.replace(".", "_") + ".bin"


def _canonical_flux_key(name: str) -> str:
    return canonical_to_tensor_key("flux." + name)


def _canonical_flux_dbl_key(index: str, name: str) -> str:
    return canonical_to_tensor_key(f"flux_dbl.{index}.{name}")


def _canonical_flux_sgl_key(index: str, name: str) -> str:
    return canonical_to_tensor_key(f"flux_sgl.{index}.{name}")


def transformer_param_to_knot_plan(param_name: str) -> TensorPlan | None:
    direct = {
        "time_text_embed.timestep_embedder.linear_1.weight": "time_in_proj.weight",
        "time_text_embed.timestep_embedder.linear_1.bias": "time_in_proj.bias",
        "time_text_embed.timestep_embedder.linear_2.weight": "time_out_proj.weight",
        "time_text_embed.timestep_embedder.linear_2.bias": "time_out_proj.bias",
        "time_text_embed.text_embedder.linear_1.weight": "vec_in_proj.weight",
        "time_text_embed.text_embedder.linear_1.bias": "vec_in_proj.bias",
        "time_text_embed.text_embedder.linear_2.weight": "vec_out_proj.weight",
        "time_text_embed.text_embedder.linear_2.bias": "vec_out_proj.bias",
        "time_text_embed.guidance_embedder.linear_1.weight": "guidance_proj.weight",
        "time_text_embed.guidance_embedder.linear_1.bias": "guidance_proj.bias",
        "time_text_embed.guidance_embedder.linear_2.weight": "guidance_out_proj.weight",
        "time_text_embed.guidance_embedder.linear_2.bias": "guidance_out_proj.bias",
        "context_embedder.weight": "txt_in.weight",
        "context_embedder.bias": "txt_in.bias",
        "x_embedder.weight": "img_in.weight",
        "x_embedder.bias": "img_in.bias",
        "proj_out.weight": "final_layer.weight",
        "proj_out.bias": "final_layer.bias",
    }
    if param_name in direct:
        return TensorPlan(_canonical_flux_key(direct[param_name]))
    if param_name == "norm_out.linear.weight":
        return TensorPlan(_canonical_flux_key("final_adaln.weight"), swap_scale_shift=True)
    if param_name == "norm_out.linear.bias":
        return TensorPlan(_canonical_flux_key("final_adaln.bias"), swap_scale_shift=True)

    import re

    double = re.match(r"^transformer_blocks\.(\d+)\.(.+)$", param_name)
    if double:
        index, suffix = double.groups()
        double_direct = {
            "norm1.linear.weight": "img_mod.weight",
            "norm1.linear.bias": "img_mod.bias",
            "norm1_context.linear.weight": "txt_mod.weight",
            "norm1_context.linear.bias": "txt_mod.bias",
            "attn.norm_q.weight": "img_q_norm.scale",
            "attn.norm_k.weight": "img_k_norm.scale",
            "attn.norm_added_q.weight": "txt_q_norm.scale",
            "attn.norm_added_k.weight": "txt_k_norm.scale",
            "ff.net.0.proj.weight": "img_fc1.weight",
            "ff.net.0.proj.bias": "img_fc1.bias",
            "ff.net.2.weight": "img_fc2.weight",
            "ff.net.2.bias": "img_fc2.bias",
            "ff_context.net.0.proj.weight": "txt_fc1.weight",
            "ff_context.net.0.proj.bias": "txt_fc1.bias",
            "ff_context.net.2.weight": "txt_fc2.weight",
            "ff_context.net.2.bias": "txt_fc2.bias",
            "attn.to_out.0.weight": "img_out.weight",
            "attn.to_out.0.bias": "img_out.bias",
            "attn.to_add_out.weight": "txt_out.weight",
            "attn.to_add_out.bias": "txt_out.bias",
        }
        if suffix in double_direct:
            return TensorPlan(_canonical_flux_dbl_key(index, double_direct[suffix]))
        qkv = {
            "attn.to_q.weight": ("img_qkv.weight", 0),
            "attn.to_k.weight": ("img_qkv.weight", 1),
            "attn.to_v.weight": ("img_qkv.weight", 2),
            "attn.to_q.bias": ("img_qkv.bias", 0),
            "attn.to_k.bias": ("img_qkv.bias", 1),
            "attn.to_v.bias": ("img_qkv.bias", 2),
            "attn.add_q_proj.weight": ("txt_qkv.weight", 0),
            "attn.add_k_proj.weight": ("txt_qkv.weight", 1),
            "attn.add_v_proj.weight": ("txt_qkv.weight", 2),
            "attn.add_q_proj.bias": ("txt_qkv.bias", 0),
            "attn.add_k_proj.bias": ("txt_qkv.bias", 1),
            "attn.add_v_proj.bias": ("txt_qkv.bias", 2),
        }
        if suffix in qkv:
            source, split_index = qkv[suffix]
            return TensorPlan(_canonical_flux_dbl_key(index, source), "qkv", split_index)
        return None

    single = re.match(r"^single_transformer_blocks\.(\d+)\.(.+)$", param_name)
    if single:
        index, suffix = single.groups()
        single_direct = {
            "norm.linear.weight": "mod.weight",
            "norm.linear.bias": "mod.bias",
            "attn.norm_q.weight": "q_norm.scale",
            "attn.norm_k.weight": "k_norm.scale",
            "proj_out.weight": "linear2.weight",
            "proj_out.bias": "linear2.bias",
        }
        if suffix in single_direct:
            return TensorPlan(_canonical_flux_sgl_key(index, single_direct[suffix]))
        linear1 = {
            "attn.to_q.weight": ("linear1.weight", 0),
            "attn.to_k.weight": ("linear1.weight", 1),
            "attn.to_v.weight": ("linear1.weight", 2),
            "proj_mlp.weight": ("linear1.weight", 3),
            "attn.to_q.bias": ("linear1.bias", 0),
            "attn.to_k.bias": ("linear1.bias", 1),
            "attn.to_v.bias": ("linear1.bias", 2),
            "proj_mlp.bias": ("linear1.bias", 3),
        }
        if suffix in linear1:
            source, split_index = linear1[suffix]
            return TensorPlan(_canonical_flux_sgl_key(index, source), "single_linear1", split_index)
    return None


def diffusers_param_to_knot_plan(
    encoder_module: Any,
    component: str,
    param_name: str,
) -> TensorPlan | None:
    if component == "transformer":
        return transformer_param_to_knot_plan(param_name)
    canonical = encoder_module._map_name(param_name, "flux", component)
    if canonical is None:
        return None
    return TensorPlan(canonical_to_tensor_key(canonical))


def diffusers_param_to_knot_key(encoder_module: Any, component: str, param_name: str) -> str | None:
    plan = diffusers_param_to_knot_plan(encoder_module, component, param_name)
    return plan.key if plan is not None else None


def apply_tensor_plan(array: Any, plan: TensorPlan, destination_shape: tuple[int, ...]):
    import numpy as np

    if plan.split_kind == "qkv":
        chunks = np.split(array, 3, axis=0)
        array = chunks[plan.split_index]
    elif plan.split_kind == "single_linear1":
        rows = int(array.shape[0])
        target_rows = int(destination_shape[0])
        if plan.split_index == 3:
            mlp_rows = target_rows
            inner_rows = (rows - mlp_rows) // 3
        else:
            inner_rows = target_rows
            mlp_rows = rows - (inner_rows * 3)
        if inner_rows <= 0 or mlp_rows <= 0 or (inner_rows * 3 + mlp_rows) != rows:
            raise ValueError(
                f"cannot split {plan.key} rows={rows} for destination shape {destination_shape}"
            )
        offsets = [0, inner_rows, inner_rows * 2, inner_rows * 3, rows]
        array = array[offsets[plan.split_index] : offsets[plan.split_index + 1]]
    if plan.swap_scale_shift:
        shift, scale = np.split(array, 2, axis=0)
        array = np.concatenate([scale, shift], axis=0)
    return array.reshape(destination_shape)


def resolve_config_model_dir(
    model: str,
    *,
    revision: str,
    hf_token: str | None,
    local_files_only: bool,
) -> Path:
    candidate = Path(model).expanduser()
    if candidate.exists():
        if not candidate.is_dir():
            raise ValueError(f"--model path is not a directory: {candidate}")
        return candidate

    from huggingface_hub import snapshot_download

    allow_patterns = [
        "model_index.json",
        "transformer/config.json",
        "vae/config.json",
        "text_encoder/config.json",
        "text_encoder_2/config.json",
        "scheduler/*",
        "tokenizer/*",
        "tokenizer_2/*",
    ]
    return Path(
        snapshot_download(
            model,
            revision=revision,
            token=hf_token,
            allow_patterns=allow_patterns,
            local_files_only=local_files_only,
        )
    )


def _json(path: Path) -> dict[str, Any]:
    with path.open() as handle:
        return json.load(handle)


def torch_dtype_from_name(torch: Any, raw: str, device: str):
    value = raw.lower()
    if value == "auto":
        if device.startswith("cuda"):
            return torch.bfloat16
        if device == "mps":
            return torch.float16
        return torch.float32
    if value in ("fp32", "float32"):
        return torch.float32
    if value in ("fp16", "float16"):
        return torch.float16
    if value in ("bf16", "bfloat16"):
        return torch.bfloat16
    raise ValueError(f"unsupported --dtype {raw!r}")


def build_empty_flux_pipeline(model_dir: Path, *, torch_dtype: Any):
    from diffusers import AutoencoderKL, FlowMatchEulerDiscreteScheduler, FluxPipeline
    try:
        from diffusers import FluxTransformer2DModel
    except ImportError:
        from diffusers.models.transformers.transformer_flux import FluxTransformer2DModel
    from transformers import CLIPTextConfig, CLIPTextModel, CLIPTokenizer
    from transformers import T5Config, T5EncoderModel, T5TokenizerFast

    transformer = FluxTransformer2DModel.from_config(_json(model_dir / "transformer" / "config.json"))
    vae = AutoencoderKL.from_config(_json(model_dir / "vae" / "config.json"))
    clip_config = CLIPTextConfig.from_json_file(str(model_dir / "text_encoder" / "config.json"))
    t5_config = T5Config.from_json_file(str(model_dir / "text_encoder_2" / "config.json"))
    text_encoder = CLIPTextModel(clip_config)
    text_encoder_2 = T5EncoderModel(t5_config)
    scheduler = FlowMatchEulerDiscreteScheduler.from_config(_json(model_dir / "scheduler" / "scheduler_config.json"))
    tokenizer = CLIPTokenizer.from_pretrained(model_dir / "tokenizer")
    tokenizer_2 = T5TokenizerFast.from_pretrained(model_dir / "tokenizer_2")

    modules = (transformer, vae, text_encoder, text_encoder_2)
    for module in modules:
        module.to(dtype=torch_dtype)

    return FluxPipeline(
        scheduler=scheduler,
        vae=vae,
        text_encoder=text_encoder,
        tokenizer=tokenizer,
        text_encoder_2=text_encoder_2,
        tokenizer_2=tokenizer_2,
        transformer=transformer,
    )


def load_component_from_knot(
    *,
    torch: Any,
    component_name: str,
    module: Any,
    reader: KnotTensorReader,
    encoder_module: Any,
    dtype: Any,
) -> tuple[int, list[str]]:
    own_state = module.state_dict()
    missing: list[str] = []
    loaded = 0
    last_key: str | None = None
    last_array: Any = None
    with torch.no_grad():
        for param_name, destination in own_state.items():
            if param_name.endswith("position_ids"):
                continue
            plan = diffusers_param_to_knot_plan(encoder_module, component_name, param_name)
            if plan is None or plan.key not in reader.tensors:
                missing.append(param_name)
                continue
            if plan.key == last_key:
                array = last_array
            else:
                array = reader.read_numpy(plan.key)
                last_key = plan.key
                last_array = array
            planned = apply_tensor_plan(array, plan, tuple(destination.shape))
            tensor = torch.from_numpy(planned.copy())
            tensor = tensor.to(dtype=dtype, device=destination.device)
            destination.copy_(tensor)
            loaded += 1
    return loaded, missing


def hydrate_pipeline_from_knot(pipe: Any, reader: KnotTensorReader, *, torch: Any, dtype: Any) -> dict[str, Any]:
    encoder_module = load_encode_knot_module()
    components = {
        "transformer": pipe.transformer,
        "vae": pipe.vae,
        "text_encoder": pipe.text_encoder,
        "text_encoder_2": pipe.text_encoder_2,
    }
    report: dict[str, Any] = {"loaded": {}, "missing": {}}
    for name, module in components.items():
        loaded, missing = load_component_from_knot(
            torch=torch,
            component_name=name,
            module=module,
            reader=reader,
            encoder_module=encoder_module,
            dtype=dtype,
        )
        report["loaded"][name] = loaded
        report["missing"][name] = missing
        if missing:
            sample = ", ".join(missing[:8])
            suffix = "..." if len(missing) > 8 else ""
            raise RuntimeError(f"KNOT missing {name} tensors for Diffusers state: {sample}{suffix}")
    return report


def generate_image(args: argparse.Namespace) -> dict[str, Any]:
    import torch

    device = args.device
    if device == "auto":
        if torch.cuda.is_available():
            device = "cuda"
        elif getattr(torch.backends, "mps", None) is not None and torch.backends.mps.is_available():
            device = "mps"
        else:
            device = "cpu"
    torch_dtype = torch_dtype_from_name(torch, args.dtype, device)

    reader = KnotTensorReader(Path(args.knot))
    problems = validate_flux_knot_metadata(reader.metadata)
    if problems:
        raise RuntimeError("FLUX KNOT is not usable: " + "; ".join(problems))

    model_dir = resolve_config_model_dir(
        args.model,
        revision=args.revision,
        hf_token=args.hf_token,
        local_files_only=args.local_files_only,
    )
    pipe = build_empty_flux_pipeline(model_dir, torch_dtype=torch_dtype)
    hydration = hydrate_pipeline_from_knot(pipe, reader, torch=torch, dtype=torch_dtype)

    if args.cpu_offload:
        pipe.enable_model_cpu_offload()
    else:
        pipe.to(device)

    generator = torch.Generator(device=device if device != "mps" else "cpu").manual_seed(args.seed)
    call_kwargs: dict[str, Any] = {
        "prompt": args.prompt,
        "num_inference_steps": args.steps,
        "guidance_scale": args.guidance,
        "width": args.width,
        "height": args.height,
        "generator": generator,
    }
    signature = inspect.signature(pipe.__call__)
    if args.negative_prompt and "negative_prompt" in signature.parameters:
        call_kwargs["negative_prompt"] = args.negative_prompt

    image = pipe(**call_kwargs).images[0]
    output = Path(args.output)
    output.parent.mkdir(parents=True, exist_ok=True)
    image.save(output)
    return {
        "status": "image-written",
        "runtime": "flux-knot-diffusers",
        "knot": str(Path(args.knot)),
        "model": str(model_dir),
        "output": str(output),
        "device": device,
        "dtype": str(torch_dtype).replace("torch.", ""),
        "steps": args.steps,
        "guidance": args.guidance,
        "seed": args.seed,
        "width": args.width,
        "height": args.height,
        "hydration": hydration,
    }


def build_arg_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Generate a FLUX image from a full FLUX KNOT through Diffusers."
    )
    parser.add_argument("--knot", required=True, help="Path to full FLUX .knot")
    parser.add_argument(
        "--model",
        default="black-forest-labs/FLUX.1-dev",
        help="Diffusers FLUX model ID or local folder for configs/tokenizers only",
    )
    parser.add_argument("--prompt", required=True)
    parser.add_argument("--output", required=True)
    parser.add_argument("--negative-prompt")
    parser.add_argument("--steps", type=int, default=20)
    parser.add_argument("--guidance", type=float, default=3.5)
    parser.add_argument("--seed", type=int, default=42)
    parser.add_argument("--width", type=int, default=1024)
    parser.add_argument("--height", type=int, default=1024)
    parser.add_argument("--device", default="auto", help="auto, cpu, cuda, cuda:0, or mps")
    parser.add_argument("--dtype", default="auto", help="auto, fp32, fp16, or bf16")
    parser.add_argument("--revision", default="main")
    parser.add_argument("--hf-token", default=os.getenv("HF_TOKEN"))
    parser.add_argument("--local-files-only", action="store_true")
    parser.add_argument("--cpu-offload", action="store_true")
    parser.add_argument("--manifest", help="Optional JSON generation report path")
    return parser


def main() -> int:
    args = build_arg_parser().parse_args()
    try:
        report = generate_image(args)
    except Exception as error:
        print(f"flux-knot-diffusers: {error}", file=sys.stderr)
        return 1

    if args.manifest:
        manifest_path = Path(args.manifest)
        manifest_path.parent.mkdir(parents=True, exist_ok=True)
        manifest_path.write_text(json.dumps(report, indent=2) + "\n")
    print(json.dumps(report, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
